meta.script:
(function(){
  const url = "https://cdn.jsdelivr.net/gh/un-zynq/singlefilegames/drift-hunters-pro.html";
  fetch(url)
    .then(r => r.text())
    .then(html => {
      const iframe = document.getElementById('gameFrame');
      const doc = iframe.contentWindow.document;
      doc.open();
      doc.write(html);
      doc.close();
    })
    .catch(e => {
      const iframe = document.getElementById('gameFrame');
      const doc = iframe.contentWindow.document;
      doc.open();
      doc.write('Error: ' + e.message + '');
      doc.close();
    });
})();
